def validate_blob_path(blob_path: str) -> bool:
    """Validate blob path to prevent path traversal and injection attacks."""
    if not blob_path:
        return False
    
    # Reject path traversal attempts
    if '..' in blob_path:
        return False
    
    # Reject absolute paths
    if blob_path.startswith('/') or blob_path.startswith('\\'):
        return False
    
    # Reject paths with null bytes
    if '\x00' in blob_path:
        return False
    
    # Only allow alphanumeric, hyphens, underscores, dots, and forward slashes
    if not re.match(r'^[a-zA-Z0-9\-_./]+$', blob_path):
        return False
    
    # Reject consecutive slashes
    if '//' in blob_path:
        return False
    
    # Reject paths ending with slash (not a file)
    if blob_path.endswith('/'):
        return False
    
    # Enforce maximum path length
    if len(blob_path) > 1024:
        return False
    
    # Normalize and re-check to catch encoded traversal
    normalized = os.path.normpath(blob_path).replace('\\', '/')
    if normalized.startswith('..') or '/..' in normalized:
        return False
    
    return True


def get_content_type(blob_path: str) -> str:
    """Return a safe content type based on file extension."""
    extension_map = {
        '.txt': 'text/plain',
        '.json': 'application/json',
        '.csv': 'text/csv',
        '.xml': 'application/xml',
        '.html': 'text/html',
        '.pdf': 'application/pdf',
        '.png': 'image/png',
        '.jpg': 'image/jpeg',
        '.jpeg': 'image/jpeg',
        '.gif': 'image/gif',
        '.svg': 'image/svg+xml',
        '.zip': 'application/zip',
        '.gz': 'application/gzip',
        '.yaml': 'application/x-yaml',
        '.yml': 'application/x-yaml',
        '.md': 'text/markdown',
    }
    
    _, ext = os.path.splitext(blob_path.lower())
    return extension_map.get(ext, 'application/octet-stream')


